// Calculate available resources by type, considering current utilization, scheduled maintenance, and upcoming reservations

// Access the query input from the AI agent
const resourceType = query || 'all';

// Get current utilization data from the workflow context
const utilizationData = $fromAI('currentUtilization', 'object') || {};
const upcomingEvents = $fromAI('upcomingEvents', 'object') || {};

// Calculate availability for different resource types
const calculateAvailability = (type) => {
  const current = utilizationData[type] || {};
  const total = current.total || 0;
  const occupied = current.occupied || 0;
  const available = current.available || 0;

  // Account for maintenance windows
  const maintenanceImpact = upcomingEvents.maintenanceWindows?.filter(m => 
    m.equipment?.toLowerCase().includes(type.toLowerCase())
  ).length || 0;

  // Account for upcoming reservations
  const reservedCount = upcomingEvents.resourceReservations?.filter(r => 
    r.resourceId?.toLowerCase().includes(type.toLowerCase())
  ).length || 0;

  const effectiveAvailable = Math.max(0, available - maintenanceImpact - reservedCount);

  return {
    type: type,
    total: total,
    occupied: occupied,
    available: available,
    effectiveAvailable: effectiveAvailable,
    utilizationRate: total > 0 ? (occupied / total) : 0,
    maintenanceImpact: maintenanceImpact,
    reservedCount: reservedCount
  };
};

// Calculate for specific type or all types
if (resourceType === 'all') {
  const availability = {
    beds: calculateAvailability('beds'),
    rooms: calculateAvailability('rooms'),
    equipment: calculateAvailability('equipment'),
    staff: calculateAvailability('staff'),
    timestamp: new Date().toISOString()
  };
  return JSON.stringify(availability, null, 2);
} else {
  const availability = calculateAvailability(resourceType);
  return JSON.stringify(availability, null, 2);
}

// Analyzes utilization metrics and identifies optimization opportunities
// Input: query should contain utilization data as JSON string or object

let utilizationData;

// Parse the query input
if (typeof query === 'string') {
  try {
    utilizationData = JSON.parse(query);
  } catch (e) {
    return 'Error: Invalid JSON input. Please provide utilization data as a valid JSON object.';
  }
} else if (typeof query === 'object') {
  utilizationData = query;
} else {
  return 'Error: Please provide utilization data as a JSON object or string.';
}

// Analyze utilization patterns
const analysis = {
  underutilizedResources: [],
  bottlenecks: [],
  efficiencyScores: {},
  recommendations: []
};

// Identify underutilized resources (< 60% utilization)
if (utilizationData.beds) {
  const bedUtilization = utilizationData.beds.occupancyRate || 0;
  if (bedUtilization < 0.6) {
    analysis.underutilizedResources.push({
      resource: 'beds',
      currentUtilization: bedUtilization,
      capacity: utilizationData.beds.total,
      available: utilizationData.beds.available
    });
    analysis.recommendations.push('Consider reducing bed capacity or marketing to increase patient admissions');
  }
  analysis.efficiencyScores.beds = bedUtilization;
}

if (utilizationData.rooms) {
  const roomUtilization = utilizationData.rooms.occupancyRate || 0;
  if (roomUtilization < 0.6) {
    analysis.underutilizedResources.push({
      resource: 'rooms',
      currentUtilization: roomUtilization,
      capacity: utilizationData.rooms.total,
      available: utilizationData.rooms.available
    });
    analysis.recommendations.push('Room utilization is low. Consider scheduling optimization or multi-purpose room usage');
  }
  analysis.efficiencyScores.rooms = roomUtilization;
}

// Detect bottlenecks (> 85% utilization)
if (utilizationData.equipment) {
  for (const [equipmentType, data] of Object.entries(utilizationData.equipment)) {
    const utilization = data.inUse / data.total;
    analysis.efficiencyScores[equipmentType] = utilization;

    if (utilization > 0.85) {
      analysis.bottlenecks.push({
        resource: equipmentType,
        currentUtilization: utilization,
        available: data.available,
        total: data.total,
        severity: utilization > 0.95 ? 'critical' : 'high'
      });
      analysis.recommendations.push(`${equipmentType} is at ${(utilization * 100).toFixed(1)}% capacity. Consider acquiring additional units or optimizing scheduling.`);
    }
  }
}

// Analyze staff utilization
if (utilizationData.staff) {
  for (const [staffType, data] of Object.entries(utilizationData.staff)) {
    const utilization = data.utilizationRate || 0;
    analysis.efficiencyScores[`staff_${staffType}`] = utilization;

    if (utilization > 0.9) {
      analysis.bottlenecks.push({
        resource: `staff_${staffType}`,
        currentUtilization: utilization,
        severity: 'high'
      });
      analysis.recommendations.push(`${staffType} utilization is ${(utilization * 100).toFixed(1)}%. Consider hiring additional staff or adjusting schedules.`);
    } else if (utilization < 0.6) {
      analysis.underutilizedResources.push({
        resource: `staff_${staffType}`,
        currentUtilization: utilization
      });
    }
  }
}

// Calculate overall efficiency score
const efficiencyValues = Object.values(analysis.efficiencyScores);
const overallEfficiency = efficiencyValues.length > 0 
  ? efficiencyValues.reduce((a, b) => a + b, 0) / efficiencyValues.length 
  : 0;

analysis.overallEfficiencyScore = overallEfficiency;
analysis.efficiencyRating = overallEfficiency > 0.8 ? 'Excellent' : 
                            overallEfficiency > 0.65 ? 'Good' : 
                            overallEfficiency > 0.5 ? 'Fair' : 'Poor';

// Add summary
analysis.summary = `Overall efficiency: ${(overallEfficiency * 100).toFixed(1)}% (${analysis.efficiencyRating}). Found ${analysis.bottlenecks.length} bottleneck(s) and ${analysis.underutilizedResources.length} underutilized resource(s).`;

return JSON.stringify(analysis, null, 2);

// Calculate comprehensive risk score for resource allocation
// Considers utilization levels, SLA violation probability, historical patterns,
// upcoming events, and resource constraints with weighted scoring algorithm

const items = $input.all();
const contextData = items[0].json;

// Extract relevant data
const currentUtilization = contextData.currentUtilization || {};
const historicalTrends = contextData.historicalTrends || {};
const upcomingEvents = contextData.upcomingEvents || {};
const slaData = contextData.slaData || {};
const requestDetails = contextData.requestDetails || {};

// Define risk scoring weights (total = 1.0)
const weights = {
  utilizationLevel: 0.30,
  slaViolationProbability: 0.25,
  historicalPatterns: 0.20,
  upcomingEvents: 0.15,
  resourceConstraints: 0.10
};

// 1. Calculate Utilization Level Risk (0-100)
let utilizationRisk = 0;
if (currentUtilization.beds) {
  const bedOccupancy = currentUtilization.beds.occupancyRate || 0;
  utilizationRisk += bedOccupancy * 40; // 40% weight for beds
}
if (currentUtilization.rooms) {
  const roomOccupancy = currentUtilization.rooms.occupancyRate || 0;
  utilizationRisk += roomOccupancy * 30; // 30% weight for rooms
}
if (currentUtilization.equipment) {
  const equipmentUtilization = Object.values(currentUtilization.equipment)
    .reduce((sum, eq) => sum + (eq.inUse / eq.total), 0) / Object.keys(currentUtilization.equipment).length;
  utilizationRisk += equipmentUtilization * 30; // 30% weight for equipment
}

// 2. Calculate SLA Violation Probability Risk (0-100)
let slaRisk = 0;
const slaThreshold = slaData.responseTimeThreshold || 30; // minutes
const currentResponseTime = slaData.currentResponseTime || 0;
if (currentResponseTime > slaThreshold) {
  slaRisk = Math.min(100, ((currentResponseTime - slaThreshold) / slaThreshold) * 100);
} else {
  slaRisk = (currentResponseTime / slaThreshold) * 50; // Lower risk if within threshold
}

// 3. Calculate Historical Patterns Risk (0-100)
let historicalRisk = 0;
if (historicalTrends.demandForecasts && historicalTrends.demandForecasts.length > 0) {
  const nearTermForecast = historicalTrends.demandForecasts[0];
  const predictedIncrease = nearTermForecast.predictedIncrease || 0;
  const confidence = nearTermForecast.confidence || 0.5;
  historicalRisk = (predictedIncrease * confidence) * 0.8; // Scale to 0-100
}

// 4. Calculate Upcoming Events Risk (0-100)
let eventsRisk = 0;
const scheduledProcedures = upcomingEvents.scheduledProcedures || [];
const maintenanceWindows = upcomingEvents.maintenanceWindows || [];
const expectedAdmissions = upcomingEvents.expectedAdmissions || [];

const totalUpcomingEvents = scheduledProcedures.length + maintenanceWindows.length + expectedAdmissions.length;
eventsRisk = Math.min(100, totalUpcomingEvents * 15); // Each event adds 15 points, max 100

// 5. Calculate Resource Constraints Risk (0-100)
let constraintsRisk = 0;
if (currentUtilization.alerts && currentUtilization.alerts.length > 0) {
  const warningAlerts = currentUtilization.alerts.filter(a => a.type === 'warning').length;
  const criticalAlerts = currentUtilization.alerts.filter(a => a.type === 'critical').length;
  constraintsRisk = (warningAlerts * 30) + (criticalAlerts * 50);
  constraintsRisk = Math.min(100, constraintsRisk);
}

// Calculate weighted total risk score (0-100)
const totalRiskScore = 
  (utilizationRisk * weights.utilizationLevel) +
  (slaRisk * weights.slaViolationProbability) +
  (historicalRisk * weights.historicalPatterns) +
  (eventsRisk * weights.upcomingEvents) +
  (constraintsRisk * weights.resourceConstraints);

// Determine risk level
let riskLevel = 'low';
if (totalRiskScore >= 75) {
  riskLevel = 'critical';
} else if (totalRiskScore >= 50) {
  riskLevel = 'high';
} else if (totalRiskScore >= 25) {
  riskLevel = 'medium';
}

// Prepare detailed risk breakdown
const riskBreakdown = {
  totalRiskScore: Math.round(totalRiskScore * 100) / 100,
  riskLevel: riskLevel,
  components: {
    utilizationLevel: {
      score: Math.round(utilizationRisk * 100) / 100,
      weight: weights.utilizationLevel,
      contribution: Math.round(utilizationRisk * weights.utilizationLevel * 100) / 100
    },
    slaViolationProbability: {
      score: Math.round(slaRisk * 100) / 100,
      weight: weights.slaViolationProbability,
      contribution: Math.round(slaRisk * weights.slaViolationProbability * 100) / 100
    },
    historicalPatterns: {
      score: Math.round(historicalRisk * 100) / 100,
      weight: weights.historicalPatterns,
      contribution: Math.round(historicalRisk * weights.historicalPatterns * 100) / 100
    },
    upcomingEvents: {
      score: Math.round(eventsRisk * 100) / 100,
      weight: weights.upcomingEvents,
      contribution: Math.round(eventsRisk * weights.upcomingEvents * 100) / 100
    },
    resourceConstraints: {
      score: Math.round(constraintsRisk * 100) / 100,
      weight: weights.resourceConstraints,
      contribution: Math.round(constraintsRisk * weights.resourceConstraints * 100) / 100
    }
  },
  recommendations: [],
  calculatedAt: new Date().toISOString()
};

// Generate recommendations based on risk level
if (riskLevel === 'critical' || riskLevel === 'high') {
  riskBreakdown.recommendations.push('Immediate resource reallocation recommended');
  riskBreakdown.recommendations.push('Consider escalating to senior management');
}
if (utilizationRisk > 80) {
  riskBreakdown.recommendations.push('Critical utilization levels detected - consider capacity expansion');
}
if (slaRisk > 70) {
  riskBreakdown.recommendations.push('High SLA violation risk - prioritize critical requests');
}
if (eventsRisk > 60) {
  riskBreakdown.recommendations.push('Multiple upcoming events - proactive resource planning needed');
}

// Return enriched data with risk score
return [{
  json: {
    ...contextData,
    riskAssessment: riskBreakdown
  }
}];

